module decision_tree (
    input [2:0] in,
    output reg [1:0] invalid_output
);
    always @(*) begin
        case (in)
            3'b000: invalid_output = 2'b00;
            3'b001: invalid_output = 2'b01;
            3'b010: invalid_output = 2'b01;
            3'b011: invalid_output = 2'b10;
            3'b100: invalid_output = 2'b10;
            3'b101: invalid_output = 2'b11;
            3'b110: invalid_output = 2'b10;
            3'b111: invalid_output = 2'b10;
            default: invalid_output = 2'b00; // Default case for safety
        endcase
    end
endmodule
